using System;\nusing System.Reflection;\nusing Mono.Data.Sqlite;\nusing TechInfoSystems.Data.SQLite;\nusing Xunit;\n\nnamespace TechInfoSystems.Data.SQLite.Tests\n{\n    public class SQLiteRoleProviderGetUsersInRoleTests\n    {\n        [Fact]\n        public void GetUsersInRole_WithRoleAndApp_UsesAtParameterMarkersAndReturnsUsers()\n        {\n            // Arrange\n            var provider = new SQLiteRoleProvider();\n            SetPrivateStaticField(typeof(SQLiteRoleProvider), \"_connectionString\", \"Data Source=:memory:;Version=3;New=True;\");\n            SetPrivateStaticField(typeof(SQLiteRoleProvider), \"_applicationId\", \"app1\");\n\n            using var cn = new SqliteConnection(\"Data Source=:memory:;Version=3;New=True;\");\n            cn.Open();\n\n            using (var cmd = cn.CreateCommand())\n            {\n                cmd.CommandText = @\"\nCREATE TABLE aspnet_Users(\n    UserId TEXT PRIMARY KEY,\n    Username TEXT,\n    LoweredUsername TEXT,\n    ApplicationId TEXT\n);\nCREATE TABLE aspnet_Roles(\n    RoleId TEXT PRIMARY KEY,\n    RoleName TEXT,\n    LoweredRoleName TEXT,\n    ApplicationId TEXT\n);\nCREATE TABLE aspnet_UsersInRoles(\n    UserId TEXT,\n    RoleId TEXT\n);\n\";\n                cmd.ExecuteNonQuery();\n            }\n\n            using (var cmd = cn.CreateCommand())\n            {\n                cmd.CommandText = \"INSERT INTO aspnet_Users(UserId, Username, LoweredUsername, ApplicationId) VALUES (@u,@un,@lun,@app);\";\n                cmd.Parameters.AddWithValue(\"@u\", \"u1\");\n                cmd.Parameters.AddWithValue(\"@un\", \"Bob\");\n                cmd.Parameters.AddWithValue(\"@lun\", \"bob\");\n                cmd.Parameters.AddWithValue(\"@app\", \"app1\");\n                cmd.ExecuteNonQuery();\n            }\n\n            using (var cmd = cn.CreateCommand())\n            {\n                cmd.CommandText = \"INSERT INTO aspnet_Roles(RoleId, RoleName, LoweredRoleName, ApplicationId) VALUES (@r,@rn,@lrn,@app);\";\n                cmd.Parameters.AddWithValue(\"@r\", \"r1\");\n                cmd.Parameters.AddWithValue(\"@rn\", \"Admin\");\n                cmd.Parameters.AddWithValue(\"@lrn\", \"admin\");\n                cmd.Parameters.AddWithValue(\"@app\", \"app1\");\n                cmd.ExecuteNonQuery();\n            }\n\n            using (var cmd = cn.CreateCommand())\n            {\n                cmd.CommandText = \"INSERT INTO aspnet_UsersInRoles(UserId, RoleId) VALUES (@u,@r);\";\n                cmd.Parameters.AddWithValue(\"@u\", \"u1\");\n                cmd.Parameters.AddWithValue(\"@r\", \"r1\");\n                cmd.ExecuteNonQuery();\n            }\n\n            // Force provider to use our connection via HttpContext transaction\n            var httpCtx = new System.Web.HttpContext(\n                new System.Web.HttpRequest(\"\", \"http://localhost/\", \"\"),\n                new System.Web.HttpResponse(new System.IO.StringWriter()));\n            System.Web.HttpContext.Current = httpCtx;\n            var tran = cn.BeginTransaction();\n            httpCtx.Items[\"SQLiteTran\"] = tran;\n\n            // Because provider's MembershipApplicationId is used in other methods, but GetUsersInRole uses _applicationId.\n\n            // Act\n            var users = provider.GetUsersInRole(\"Admin\");\n\n            // Assert\n            Assert.Single(users);\n            Assert.Equal(\"Bob\", users[0]);\n        }\n\n        private static void SetPrivateStaticField(Type t, string fieldName, object value)\n        {\n            var f = t.GetField(fieldName, BindingFlags.Static | BindingFlags.NonPublic);\n            Assert.NotNull(f);\n            f!.SetValue(null, value);\n        }\n    }\n}\n